protected override void OnModelCreating(ModelBuilder modelBuilder)
{
    modelBuilder.Entity<Product>(entity =>
    {
        entity.ToContainer("Products");

        // EF Core 9 changed the default discriminator property from "Discriminator" to "$type".
        // Existing documents and direct SQL queries use "Discriminator", so preserve it.
        entity.HasDiscriminator<string>("Discriminator");

        // EF Core 9 changed id format from "Product|123" to "123".
        // Existing 500K documents use the old compound format; preserve it.
        entity.HasRootDiscriminatorInJsonId(true);
    });

    // HasIndex was removed: Cosmos DB indexing is managed via the container's
    // indexing policy (Azure Portal / Bicep / Terraform), not EF Core.
    // The previous HasIndex(p => p.Sku) call now throws at startup.
}

